    {
      "n": 28,
      "column": "right",
      "text": "Kaß fawu Prahtu ne\nmahk niſtureht/ tas irr ka at-\nwehrts iſpohſichts Pilſfayts bes\nMuhrreem.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ta XXVI. Nodalla.\nRunna no tahdeem faudim/ kaß ne irr fohti\nGohdā turrami/ ka tee Gefki: 1. TeeGlinki:\n13. Tee Rehjeji un Babreji :17.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ka Sneegß Waffaram /\nRun Leetus vtanjamam\nLaikam/ ta patt Gohdē\nGeekam ne klaḥjahs.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Itt ka Putnis noliddina/\nitt ka Besdeliga aiſkreem / ta\npatt ne aiṣrem tee nenepelniti\nLahti.\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Sirgam peenahk Pahta-\nga/ Ehsetam Gemanti/ un Geṭa\nMugguram Rihſte.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Ne atbildi Gefkim pehz fa-\nwas Geflibas/ ka tu wiẍnam\nlihdſi ne tohpi.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Atbildi Gefkam pehz fawas\nGeffibas/ ka wiṡch patś par\nGudru ne turrahs.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Kaß Wehſtus fuhta zaur\nGeṭa Rohku/ tas irr ka kas no-\nzehrt tahs Kahjas/ un bauda\nWarras-Darbu.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Ka Krohypain danzaht/ ta\nir Gefkam klaḥjahs no Gudribas\nrunnaht.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Kaß Gefkam Gohdu pa-\nrahda/ tas irr itt ka kas (oahr-\ngu) Akmint Linga eeleek.\n"
    },
